import{_ as s,o as i,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：PLL 带宽取舍","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PLL 带宽取舍","tags":["power-electronics"],"status":"learning","summary":"锁相环（phase-locked loop / PLL）的带宽（bandwidth）描述它愿意多快相信相位误差信号。带宽高，PLL 对相位阶跃和频率变化反应快；带宽低，PLL 对噪声和谐波更不敏感，但跟踪会慢。"},"headers":[],"relativePath":"content/power/concepts/control/single-phase-pll-bandwidth.md","filePath":"content/power/concepts/control/single-phase-pll-bandwidth.md","lastUpdated":null}'),t={name:"content/power/concepts/control/single-phase-pll-bandwidth.md"};function n(p,a,h,o,d,r){return i(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-pll-带宽取舍" tabindex="-1">概念：PLL 带宽取舍 <a class="header-anchor" href="#概念-pll-带宽取舍" aria-label="Permalink to &quot;概念：PLL 带宽取舍&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>锁相环（phase-locked loop / PLL）的带宽（bandwidth）描述它愿意多快相信相位误差信号。带宽高，PLL 对相位阶跃和频率变化反应快；带宽低，PLL 对噪声和谐波更不敏感，但跟踪会慢。</p><p>本节只讲一个概念：PLL 带宽不是越高越好，而是在响应速度和噪声敏感度之间取舍。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里，PLL 角度会被功率因数校正（power factor correction / PFC）、旁路（bypass）同步和逆变器控制复用。如果 PLL 太慢，旁路同步或电网扰动后恢复会慢；如果 PLL 太快，输入电压噪声、谐波和采样毛刺会变成角度抖动，进一步影响电流参考或并联系统同步。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>PLL 像一个追着电网相位转的指针。高带宽像“方向盘很灵”：转得快，但路面小抖动也会传到方向盘。低带宽像“方向盘更稳”：小抖动不明显，但急转弯跟得慢。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>同步旋转坐标系（synchronous reference frame / SRF）PLL 可简化为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vq = sin(theta_grid - theta_hat)</span></span>
<span class="line"><span>omega_hat = omega_nominal + Kp * vq + integral(Ki * vq)</span></span>
<span class="line"><span>theta_hat[k+1] = theta_hat[k] + omega_hat * Ts</span></span></code></pre></div><p>在这个教学模型里，较大的 <code>Kp</code> 和 <code>Ki</code> 代表较高带宽。相同的相位噪声（phase noise）输入下，高带宽 PLL 的估算频率（estimated frequency / f_est）会有更明显的纹波。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_bandwidth.py</span></span></code></pre></div><p>观察：</p><ul><li>快 PLL 的相位误差更快进入 ±5 度范围。</li><li>快 PLL 的估算频率纹波更大。</li><li>慢 PLL 的频率估算更平滑，但相位阶跃后收敛更慢。</li></ul><p>一个仿真任务：改变相位噪声幅值，观察快 PLL 和慢 PLL 的相位收敛速度与估算频率纹波。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_bandwidth.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">noise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deg </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pll_bandwidth_low_noise.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_bandwidth.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">noise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deg </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pll_bandwidth_high_noise.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里带宽通常不是直接写一个 “bandwidth” 变量，而是体现在 PI 增益、滤波器、限幅和锁定判据里：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>phase detector vq</span></span>
<span class="line"><span>  -&gt; optional filter</span></span>
<span class="line"><span>  -&gt; PI gains Kp, Ki</span></span>
<span class="line"><span>  -&gt; frequency limit</span></span>
<span class="line"><span>  -&gt; phase accumulator</span></span>
<span class="line"><span>  -&gt; lock detector</span></span></code></pre></div><p>工程上要关注：</p><ul><li>PFC、旁路同步、并机同步可能使用不同的 PLL 带宽或锁定条件。</li><li>输入电压质量差时，PLL 前端滤波和带宽选择同样重要。</li><li>频率估算需要限幅，防止噪声或采样异常造成相位飞掉。</li><li>锁定判断要看持续时间内的相位误差和频率误差，而不是单点值。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：带宽越高，PLL 越高级。<br> 正确理解：带宽高只是响应快，不代表抗噪好。</p></li><li><p>错误理解：带宽只影响相位误差。<br> 正确理解：带宽还影响估算频率抖动，进而影响依赖角度的电流参考和同步判断。</p></li><li><p>错误理解：仿真里锁得快，工程里也一定好。<br> 正确理解：真实电网有谐波、跌落、过零畸变和采样噪声，必须看扰动下表现。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 PLL 带宽为什么影响响应速度。</li><li>能解释高带宽为什么更容易把相位噪声变成 <code>f_est</code> 纹波。</li><li>能在图中指出慢 PLL、快 PLL、相位误差、估算频率和频率纹波 RMS。</li><li>能说明为什么 PFC 和旁路同步可能不使用同一个带宽。</li><li>能基于 <code>single_phase_pll_bandwidth.py</code> 生成的仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么快 PLL 相位收敛更快，但频率估算更抖？</li><li>如果电网电压含明显谐波，你会倾向提高还是降低 PLL 带宽？为什么？</li><li>如果旁路切换要求很快确认同步，带宽和锁定判据应怎样一起考虑？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pll_bandwidth.py</code> 看到快 PLL 收敛快，但 <code>f_est</code> 纹波更大。公司 UPS 的 PFC、旁路同步和逆变同步是否使用不同 PLL 带宽？</li><li>图中相位噪声为 2 度时，快 PLL 的频率纹波明显更大。实际代码里是否会对 <code>vq</code> 或 <code>f_est</code> 做滤波？</li><li>公司平台的 PLL 锁定判据是固定 ±几度、固定频率误差，还是随模式和电网质量变化？</li></ul>`,33)])])}const u=s(t,[["render",n]]);export{k as __pageData,u as default};
